// Позволяет импортировать общие .mjs-модули поиска/валидации/очереди (см.
// search.mjs, validate.mjs, queue.mjs, humanize.mjs) как из React-компонентов
// админки, так и из Node CLI-скриптов — без второй, типизированной копии.
// Эти модули сознательно сделаны как plain JS (без TS/сборки), чтобы
// оставаться исполняемыми напрямую в Node (CLI) без транспиляции.
declare module "*.mjs";
